// src/pages/RiderLogin.jsx
import React, { useState } from "react";
import { Button, TextField, Typography, Alert, CircularProgress, Paper, Container, Box } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { sendOtp, verifyOtp } from "../services/api";

export default function RiderLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [otpSent, setOtpSent] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleSendOtp = async () => {
    if (!/^[6-9]\d{9}$/.test(mobile)) { setError("Invalid mobile number."); return; }
    setLoading(true); setError(""); setSuccess("");
    try {
      const res = await sendOtp(mobile, "rider");
      if (res.data?.success) { setOtpSent(true); setSuccess("OTP sent!"); }
      else setError(res.data?.message || "Failed to send OTP");
    } catch (err) { console.error(err); setError("Server error. Try again."); }
    finally { setLoading(false); }
  };

  const handleVerifyOtp = async () => {
    if (otp.length !== 6) { setError("Enter 6-digit OTP."); return; }
    setLoading(true); setError(""); setSuccess("");
    try {
      const res = await verifyOtp(mobile, otp, "rider");
      if (res.data?.success) {
        const { token, role, approved } = res.data.data;
        if (!approved) { setError("Waiting for admin approval."); setLoading(false); return; }
        localStorage.setItem("token", token);
        localStorage.setItem("role", role);
        navigate("/rider-dashboard");
      } else { setError(res.data?.message || "OTP verification failed."); }
    } catch (err) { console.error(err); setError("Server error. Try again."); }
    finally { setLoading(false); }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, boxShadow: 3, textAlign: "center" }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>Rider Login</Typography>
        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <Box>
          <TextField fullWidth label="Mobile Number" value={mobile} onChange={(e) => setMobile(e.target.value)} margin="normal" inputProps={{ maxLength: 10 }} disabled={otpSent} />
          {otpSent && <TextField fullWidth label="OTP" value={otp} onChange={(e) => setOtp(e.target.value)} margin="normal" inputProps={{ maxLength: 6 }} />}

          {!otpSent ?
            <Button fullWidth variant="contained" color="primary" sx={{ mt: 2, py: 1.5, fontWeight: "bold" }} onClick={handleSendOtp} disabled={loading}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
            </Button> :
            <Button fullWidth variant="contained" color="success" sx={{ mt: 2, py: 1.5, fontWeight: "bold" }} onClick={handleVerifyOtp} disabled={loading}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP"}
            </Button>
          }

          <Typography sx={{ mt: 3 }}>
            Don’t have a rider account? <Button onClick={() => navigate("/rider-register")} size="small">Signup</Button>
          </Typography>
          <Typography sx={{ mt: 1 }}>
            Are you a User? <Button onClick={() => navigate("/login")} size="small">Login as User</Button>
          </Typography>
        </Box>
      </Paper>
    </Container>
  );
}
